def trimmed_mean(nums):
    if not nums or len(nums) < 3:
        return None

    nums = sorted(nums)
    min_occ, max_occ = nums[0] == nums[-1], nums[-1] == nums[-2]
    if min_occ:
        nums.pop(0)
    else:
        nums[0] = None
    if max_occ:
        nums.pop(-1)
    else:
        nums[-1] = None
    return sum(filter(None, nums)) / (len(nums)-2)
